import React, { useState } from "react";

export default function Participants() {
  const [form, setForm] = useState({
    cosplayname: "",
    character: "",
    game: "",
    characterImage: null,
    cosplayImages: [],
    wipImages: [],
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    const { name, files } = e.target;
    setForm((prev) => ({ ...prev, [name]: name === "characterImage" ? files[0] : Array.from(files) }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = new FormData();
    data.append("cosplayname", form.cosplayname);
    data.append("character", form.character);
    data.append("game", form.game);
    data.append("characterImage", form.characterImage);
    form.cosplayImages.forEach((file) => data.append("cosplayImages", file));
    form.wipImages.forEach((file) => data.append("wipImages", file));

    try {
      const res = await fetch("http://localhost:4000/api/participants", {
        method: "POST",
        body: data,
      });
      if (res.ok) alert("Teilnehmer gespeichert!");
      else alert("Fehler beim Speichern");
    } catch (err) {
      alert("Serverfehler");
    }
  };

  return (
    <div className="p-6 max-w-xl mx-auto bg-green-100 rounded-2xl shadow">
      <h2 className="text-2xl font-bold text-green-800 mb-4">Teilnehmer anlegen</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <input
          name="cosplayname"
          type="text"
          placeholder="Cosplayname"
          onChange={handleChange}
          className="w-full p-2 rounded-xl border"
          required
        />
        <input
          name="character"
          type="text"
          placeholder="Charakter"
          onChange={handleChange}
          className="w-full p-2 rounded-xl border"
          required
        />
        <input
          name="game"
          type="text"
          placeholder="Game"
          onChange={handleChange}
          className="w-full p-2 rounded-xl border"
          required
        />
        <div>
          <label className="block mb-1 font-medium">Charakterbild:</label>
          <input name="characterImage" type="file" accept="image/*" onChange={handleFileChange} required />
        </div>
        <div>
          <label className="block mb-1 font-medium">Cosplaybilder:</label>
          <input name="cosplayImages" type="file" accept="image/*" multiple onChange={handleFileChange} />
        </div>
        <div>
          <label className="block mb-1 font-medium">WIP-Bilder:</label>
          <input name="wipImages" type="file" accept="image/*" multiple onChange={handleFileChange} />
        </div>
        <button type="submit" className="bg-green-500 text-white px-4 py-2 rounded-xl hover:bg-green-600">
          Speichern
        </button>
      </form>
    </div>
  );
}
